    'guida.profile.student.body': '<ol style="padding-left:20px; line-height:2;"><li>Import the manual (.epub)</li><li>Navigate to the chapter to study (TOC sidebar)</li><li>Read + highlight: yellow = concepts, green = examples, pink = terms</li><li>Extract the chapter (current + sublevels)</li><li>Save snapshot <em>"Base reading"</em></li><li>Add important selections to the collection</li><li>Save snapshot <em>"After chunk collection"</em></li><li>Open Noesis Editor → structure with H1/H2 and lists using the Inspect Panel</li><li>Export to PDF for submission</li></ol>',
    'guida.profile.researcher.btn': '🔬 Researcher — Deep workflow',
    'guida.profile.researcher.body': '<ol style="padding-left:20px; line-height:2;"><li>Import the paper/monograph (.epub)</li><li>Enable browser translation if in a foreign language</li><li>Select charts and images → add to collection (base64)</li><li>Select relevant quotes → collection</li><li>Save snapshot <em>"First review"</em></li><li>Export collection as JSON (backup)</li><li>Continue analysis, add annotations → save snapshot <em>"Full annotations"</em></li><li>Extract a chapter → Noesis Editor opens with chunks in Inspect Panel → structure the report</li><li>Export to DOCX for collegial review</li></ol>',
    'guida.profile.blogger.btn': '📝 Blogger/Creator — Fast workflow',
    'guida.profile.blogger.body': '<ol style="padding-left:20px; line-height:2;"><li>Read the book with Noesis</li><li>Select passages for the review → collection</li><li>Extract relevant chapters</li><li>Save snapshot <em>"Collected material"</em></li><li>Extract the chapter → Noesis Editor opens directly</li><li>Write the review in the WYSIWYG editor</li><li>Copy HTML → paste into CMS</li></ol>',
    'guida.profile.multilingual.btn': '🌍 Multilingual reader — Language study',
    'guida.profile.multilingual.body': '<ol style="padding-left:20px; line-height:2;"><li>Import novel in target language</li><li>Enable browser translation for native language</li><li>Read with dual reference (original + translation)</li><li>Highlight new words (pink)</li><li>Extract the chapter → Save snapshot <em>"Session 1 vocabulary"</em></li><li>Add difficult sentences to collection</li><li>Export collection JSON → personal archive</li></ol>',

    // ════════════════════════════════════════
