    // ════════════════════════════════════════
    'library.meta.desc': 'Noesis Library: manage your EPUB library, browse the books-chapters-snapshots hierarchy and access Noesis Editor in standalone mode.',
    'library.hero.badge': 'Environment · Noesis Library',
    'library.hero.h1': 'Noesis Library — <em>your knowledge library</em>',
    'library.hero.p': 'The Noesis entry point. Manage your EPUB collection, browse the books → chapters → snapshots hierarchy, and access Noesis Editor directly from the library.',
    'library.overview.label': 'Overview',
    'library.overview.h2': 'A <em>hierarchical</em> archive',
    'library.overview.p': 'Noesis Library organises your knowledge on three levels: each <strong>book</strong> shows <strong>extracted chapters</strong>, and each chapter exposes its <strong>snapshots</strong> saved over time — all accessible with one click.',
    'library.card.books.h': 'Books',
    'library.card.books.p': 'Each imported EPUB appears with cover, title, author and number of extracted chapters. Click the cover to open the book in <strong>Noesis Reading</strong>.',
    'library.card.chapters.h': 'Extracted chapters',
    'library.card.chapters.p': 'Below each book appear the chapters you have extracted. Click on the chapter name to open the most recent snapshot directly in <strong>Noesis Editor</strong>.',
    'library.card.snapshots.h': 'Snapshots',
    'library.card.snapshots.p': 'Each chapter shows its snapshots with name, variant (annotated / clean / origin) and save date. Click on a specific snapshot to open that exact version in the editor.',
    'library.img.library': 'Noesis Library — books, extracted chapters and snapshots hierarchy',
    'library.img.library.caption': '📚 Noesis Library — book grid with extracted chapters hierarchy and version snapshots',
    'library.toolbar.label': 'Toolbar',
    'library.toolbar.h2': 'The <em>Library</em> button bar',
    'library.toolbar.p': 'The top-right toolbar collects all global library commands.',
    'library.img.toolbar': 'Library button bar',
    'library.img.toolbar.caption': 'Library button bar',
    'library.btn.addbook.h': 'ADD BOOK',
    'library.btn.addbook.p': 'Opens the browser file picker. Select one or more <code>.epub</code> files from your device. The book is saved in <code>noesisLibraryDB</code> (IndexedDB) and appears immediately in the grid.',
    'library.btn.import.h': 'Import Snapshots',
    'library.btn.import.p': 'Imports snapshot files previously saved to the filesystem (HTML files with Noesis meta tags). The system reads the embedded <code>chapterId</code> and book name and automatically updates the hierarchy.',
    'library.btn.editor.h': 'Open Editor',
    'library.btn.editor.p': 'Opens Noesis Editor in standalone mode, without a pre-loaded chapter. Ideal for creating documents from scratch or from a collection imported via JSON.',
    'library.btn.tools.h': 'Tools ▾',
    'library.btn.tools.p': 'Dropdown with additional tools: <strong>Pandoc Online</strong> (document conversions in-browser via pandoc.wasm) and <strong>PDF.js Viewer</strong> (high-quality PDF rendering).',
    'library.books.label': 'Book management',
    'library.books.h2': 'Managing <em>books</em>',
    'library.books.p': 'Each book card in the library offers contextual controls for managing the title and its related content.',
    'library.book.open.h': 'Open in Reader',
    'library.book.open.p': 'Click anywhere on the book cover to open it in Noesis Reading. The reader automatically restores the last saved state (position, theme, font size).',
    'library.book.delete.h': 'Delete book',
    'library.book.delete.p': 'The red ✕ button permanently removes the book from IndexedDB and all associated chapter metadata from noesisDB. The snapshot files on the filesystem are <strong>not</strong> deleted — they remain available for future reimport.',
    'library.book.mozilla.h': 'Firefox compatibility',
    'library.book.mozilla.p': 'On Firefox, the Library is fully functional. The only difference is that the Tools dropdown may not show the Pandoc Online tool. All other features — import, reader, editor, snapshots — work identically.',
    'library.img.mozilla': 'Mozilla PDF.js Viewer — extracted chapter',
    'library.img.mozilla.caption': '🦊 Mozilla PDF.js Viewer — high-quality rendering of extracted chapters',
    'library.chapters.label': 'Chapters and snapshots',
    'library.chapters.h2': 'The <em>hierarchical</em> structure',
    'library.chapters.p': 'The hierarchical structure below each book card gives instant access to all extracted work.',
    'library.ch.variants.h': 'Snapshot variants',
    'library.ch.variants.p': 'Each saved snapshot generates two variants: <code>_annot</code> (with highlight colours preserved) and <code>_clean</code> (clean version without colour formatting, ideal for reading or export). The <code>_origin</code> is the snapshot automatically saved at extraction time.',
    'library.ch.click.h': 'Direct navigation',
    'library.ch.click.p': 'Click on the chapter name → opens the most recent snapshot. Click on a specific snapshot → opens that exact version in Noesis Editor. No intermediate dialogs.',
    'library.ch.delete.h': 'Delete snapshot',
    'library.ch.delete.p': 'Each snapshot row has a delete button. Removing a snapshot from the library only deletes the IndexedDB metadata record — the HTML file on the filesystem is not touched.',
    'library.btn.theme.h': 'Themes ▾',
    'library.btn.theme.p': 'Opens a dropdown to select the Library theme: <strong>Light</strong> or <strong>Dark</strong>. The selection applies immediately and is saved in localStorage.',
    'library.btn.help.h': 'Help Overlay',
    'library.btn.help.p': 'Opens a contextual help panel with the main instructions for using the Library. Also shown at first launch.',
    'library.tools.label': 'Tools',
    'library.tools.h2': 'Accessory <em>tools</em>',
    'library.tools.p': 'The <strong>Tools ▾</strong> dropdown in the toolbar collects the built-in support tools.',
    'library.tools.epub.h': 'noesis-epub-tools',
    'library.tools.epub.p': 'Direct access to internal helper tools: <strong>ePub Slimmer</strong> (single file compression), <strong>Multi ePub Slimmer</strong> (batch up to 10 files) and <strong>ePub Splitter</strong> (creates standalone EPUB from selected chapters). <a href="helpers.html" style="color:var(--violet);">Helper documentation →</a>',
    'library.tools.pandoc.h': 'Pandoc Online',
    'library.tools.pandoc.p': 'Opens Pandoc Online in a new tab — universal document converter. Useful for transforming files exported from Noesis Editor into other formats (LaTeX, RST, ODT, etc.).',
    'library.tools.pdfjs.h': 'Mozilla PDF Viewer',
    'library.tools.pdfjs.p': 'Opens Mozilla PDF.js in a new tab. View, search and print any PDF file with high-quality rendering, without leaving the Noesis ecosystem.',
    'library.tools.img': 'Noesis Library — Tools dropdown open with three options',
    'library.tools.img.caption': '🛠️ Tools dropdown — noesis-epub-tools, Pandoc Online, Mozilla PDF Viewer',
    'library.standalone.label': 'Noesis Editor',
    'library.standalone.h2': 'Open the editor in <em>standalone</em> mode',
    'library.standalone.p': 'You don\'t need to extract a chapter to use Noesis Editor. The <strong>Open Editor</strong> button in the toolbar launches the editor in standalone mode — an empty document ready for any content.',
    'library.standalone.mode.h': 'Standalone mode',
    'library.standalone.mode.p': 'Empty editor with the full toolbar. You can write, format, insert tables and images, and use Excalidraw exactly as in <em>chapter</em> mode.',
    'library.standalone.chunks.h': 'Import chunks from collection',
    'library.standalone.chunks.p': 'Even in standalone mode, the collection Inspect Panel is available. You can inject chunks collected during previous reading sessions into the current document.',
    'library.standalone.callout': '<strong>Editor always in a new tab</strong> — Noesis Editor always opens in a separate browser tab, whether from Library (standalone) or from Noesis Reading (chapter). You can have Library, Reading and Editor open simultaneously.',
    'library.standalone.link': 'Noesis Editor documentation →',

