    'reading.meta.desc': 'Noesis Reading: read EPUBs, annotate with 3-colour highlighting, manage bookmarks, customise themes and typography, and extract chapters into Noesis Editor.',
    'reading.hero.badge': 'Environment · Noesis Reading',
    'reading.hero.h1': 'Noesis Reading — <em>read, annotate, extract</em>',
    'reading.hero.p': 'The EPUB reading environment with hierarchical TOC, 15 themes, 3-colour highlighting, bookmarks and direct chapter extraction into Noesis Editor.',
    'reading.toolbar.label': 'Menu Bar',
    'reading.toolbar.h2': 'The <em>Reader</em> menu bar',
    'reading.toolbar.p': 'The Noesis Reading menu bar collects all reading and annotation controls. It is always visible at the top of the screen.',
    'reading.img.buttons': 'Noesis Reading menu bar',
    'reading.img.buttons.caption': 'Library · TOC · Bookmarks · Display · Navigate [Page/Scroll] · Annotate · Extract · Help',
    'reading.btn.library.h': 'Library',
    'reading.btn.library.p': 'Returns to Noesis Library. Reading position is saved automatically every 3 seconds — no manual action required.',
    'reading.btn.sidebar.h': 'TOC',
    'reading.btn.sidebar.p': 'Opens/closes the expandable Table of Contents panel. Supports up to 3 nesting levels. Click any entry to navigate directly to that section.',
    'reading.btn.bookmarks.h': 'Bookmarks',
    'reading.btn.bookmarks.p': 'Opens the bookmarks panel. Add a custom bookmark for the current position with title and date. Saved in <code>localStorage</code>.',
    'reading.btn.highlight.h': 'Annotate',
    'reading.btn.highlight.p': 'Contextual popup that appears next to selected text with 3 colour options + remove. Select text → popup appears → click colour to highlight instantly. No dropdown, no toggle. Yellow (general concepts), Green (examples/key points), Pink (terms/names), ✕ Remove. Highlights are CFI-based and survive page reload.',
    'reading.btn.display.h': 'Display Settings',
    'reading.btn.display.p': 'Unified accordion panel with: 15 reading themes in 5 groups, font size, line height, page width, font family, background and text colour pickers.',
    'reading.btn.scroll.h': 'Navigate',
    'reading.btn.scroll.p': 'Opens a dropdown to switch between <strong>Page Mode</strong> and <strong>Scroll Mode</strong>. A badge always shows the active mode: Navigate [Page] or Navigate [Scroll]. Selecting a different mode recreates the rendition immediately.',
    'reading.btn.percent.h': '% Progress',
    'reading.btn.percent.p': 'Shows current reading progress as a percentage. Click to jump to a specific percentage in the book.',
    'reading.btn.savestate.h': 'Save State',
    'reading.btn.savestate.p': 'Saves the current state: chapter position, all display settings (theme, font, size, colours). State is automatically restored when you reopen the book from the library.',
    'reading.btn.extract.h': 'Extract',
    'reading.btn.extract.p': 'Extraction dropdown: current chapter only, or current + all sublevels. Opens Noesis Editor in a new tab with content already loaded.',
    'reading.modes.label': 'Reading Modes',
    'reading.modes.h2': 'Three ways to <em>read</em>',
    'reading.modes.p': 'Choose the mode that best suits your device and reading style. You can switch at any time via <strong>Navigate</strong> in the menu bar.',
    'reading.modes.single.h': 'Single Page',
    'reading.modes.single.p': 'One page at a time with side arrow navigation. Ideal for small screens, tablets and focused reading.',
