    'reading.modes.double.p': 'Two side-by-side pages simulating an open book. Optimal for wide screens (>1024px). Activates automatically based on window width.',
    'reading.modes.scroll.h': 'Continuous Scroll',
    'reading.modes.scroll.p': 'Uninterrupted vertical flow. Ideal for immersive reading and fast scrolling. Arrow buttons are automatically hidden.',
    'reading.toc.label': 'Sidebar TOC',
    'reading.toc.h2': 'Hierarchical <em>index</em>',
    'reading.toc.p': 'The sidebar shows the book\'s Table of Contents as an expandable tree up to 3 levels deep.',
    'reading.toc.nav.h': 'Chapter navigation',
    'reading.toc.nav.p': 'Click any entry in the index to navigate directly to that chapter. Position updates in real time.',
    'reading.toc.expand.h': 'Expand / Collapse',
    'reading.toc.expand.p': '<strong>▸</strong> = expandable node, <strong>▾</strong> = expanded node, <strong>•</strong> = leaf (no sub-levels).',
    'reading.toc.depth.h': 'Hierarchy depth',
    'reading.toc.depth.p': 'Supports nested TOC structures up to 3 levels — chapters, sub-chapters and specific sections all navigable.',
    'reading.toc.empty.h': 'EPUB without TOC',
    'reading.toc.empty.p': 'If the sidebar is empty, the book has no defined index. You can still navigate with arrows or in continuous scroll.',
    'reading.nav.label': 'Navigation',
    'reading.nav.h2': '<em>Floating</em> navigation buttons',
    'reading.nav.left.h': 'Left Arrow',
    'reading.nav.left.p': 'Previous page or chapter. Hidden in scroll mode and at the first chapter of the book.',
    'reading.nav.right.h': 'Right Arrow',
    'reading.nav.right.p': 'Next page or chapter. Appears as a circular button on the right side of the screen.',
    'reading.nav.click.h': 'Side click',
    'reading.nav.click.p': 'In paginated mode: click on the left half to go back, click on the right half to go forward. Fast alternative to buttons.',
    'reading.display.label': 'Display Settings',
    'reading.display.h2': 'Typography, themes and interface <em>in one panel</em>',
    'reading.display.p': 'The <strong>Display</strong> button opens a unified accordion panel with all display controls: typography, reading themes and interface colours.',
    'reading.display.fontsize.h': 'Font Size',
    'reading.display.fontsize.p': '<strong>A−</strong> and <strong>A+</strong> buttons to reduce or increase text. Range: 50%–200% of the EPUB\'s base size.',
    'reading.display.lineheight.h': 'Line Height',
    'reading.display.lineheight.p': '<strong>≡−</strong> and <strong>≡+</strong> buttons for line spacing. Range: 1.0–1.8. Wider spacing improves readability on dense text.',
    'reading.display.single.h': 'Single Page',
    'reading.display.single.p': 'Forces single-column display regardless of screen width.',
    'reading.display.double.h': 'Double Page',
    'reading.display.double.p': 'Forces two-column side-by-side display simulating an open book.',
    'reading.display.img': 'Noesis Reading — dual page mode with Display panel open',
    'reading.display.img.caption': '👁 Display Settings — typography and page layout in the accordion panel',
    'reading.display.tip': '<strong>Per-book preferences</strong> — Typography settings are saved per book via the floating prompt that appears when the Display panel is closed after making changes. Each EPUB remembers its own configuration.',
    'reading.themegroup.warm': 'Warm',
