    'reading.themegroup.night': 'Night',
    'reading.themes.callout': '<strong>True Black for OLED</strong> — The True Black theme uses absolute black background (#000000) — ideal for OLED/AMOLED screens because switched-off pixels consume no energy.',
    'reading.interface.label': 'Display Settings — Interface',
    'reading.interface.h2': '<em>Interface</em> settings',
