    'reading.interface.opacity.p': 'Slider 0–100%: adjusts the opacity of the toolbar and controls. Reduce it for a more immersive experience.',
    'reading.hl.none.h': 'None / Remove',
    'reading.hl.none.p': 'Deactivates the active highlight. Select "None" and click on highlighted text to remove the colour.',
    'reading.highlight.callout': '<strong>Reader highlights stay in the reader</strong> — Noesis Editor has its own inline highlighting system based on Summernote. The two systems are independent and operate on their respective interfaces.',
    'reading.bookmark.create.h': 'Create a bookmark',
    'reading.bookmark.create.p': 'Click <strong>Bookmarks</strong> in the menu bar → the My Bookmarks panel opens → click <strong>New Bookmark</strong>. The bookmark saves the exact CFI position of the cursor in the text.',
    'reading.bookmark.panel.h': 'My Bookmarks panel',
    'reading.bookmark.panel.p': 'List of all bookmarks for the current book, ordered by creation date. Each entry shows title, surrounding text preview and date.',
    'reading.bookmark.goto.h': 'Go to a bookmark',
    'reading.bookmark.goto.p': 'Click any bookmark in the panel to navigate directly to that position in the text.',
    'reading.bookmark.del.h': 'Delete a bookmark',
    'reading.bookmark.del.p': 'Click the X next to the bookmark to remove it. Removal is immediate and updates the button badge.',
    'reading.savestate.label': 'Persistence',
    'reading.savestate.h2': 'Auto-save — <em>always synced</em>',
    'reading.savestate.p': 'Reading position is saved <strong>automatically every 3 seconds</strong> without any user action. Display settings (theme, typography, layout) are saved per book via a floating prompt that appears for 8 seconds when the Display panel is closed after making changes.',
    'reading.savestate.what.h': 'What is saved',
