    'editor.toolbar.tools.h': 'TOOLS',
    'editor.toolbar.tools.p': 'Apre il pannello strumenti con accesso agli helper integrati: Excalidraw, Pandoc Online e Mozilla PDF Viewer.',
    'editor.sn.ai.h': '✨ AI Assistant',
    'editor.sn.ai.p': 'Primo pulsante della toolbar. Apre il pannello AI con funzioni di riepilogo, riformulazione e analisi del testo selezionato nell\'editor.',
    'editor.sn.inline.h': 'Formattazione inline',
