    'notes.hero.badge': 'Notes de version',
    'notes.hero.h1': 'Changelog, <em>Limites</em> et Conseils',
    'notes.hero.p': 'Historique des versions, problèmes connus et suggestions pour tirer le meilleur de Noesis.',
    'notes.changelog.label': 'Changelog',
