    'guida.profile.label': 'Perfiles de usuario',
    'guida.profile.h2': 'Caminos <em>recomendados</em>',
    'guida.profile.student.btn': '🎓 Estudiante — Flujo de estudio',
    'guida.profile.student.body': '<ol style="padding-left:20px; line-height:2;"><li>Importa el manual (.epub)</li><li>Navega al capítulo a estudiar (TOC lateral)</li><li>Lee + resaltado: amarillo = conceptos, verde = ejemplos, rosa = términos</li><li>Extrae el capítulo (actual + subniveles)</li><li>Guarda instantáneo <em>"Lectura base"</em></li><li>Añade selecciones importantes a la colección</li><li>Guarda instantáneo <em>"Después de collectar chunks"</em></li><li>Abre Noesis Editor → estructura con H1/H2 y listas usando el Panel de Inspección</li><li>Exporta a PDF para entregar</li></ol>',
    'guida.profile.researcher.btn': '🔬 Investigador — Flujo profundo',
    'guida.profile.researcher.body': '<ol style="padding-left:20px; line-height:2;"><li>Importa el paper/monografía (.epub)</li><li>Habilita traducción del navegador si está en idioma extranjero</li><li>Selecciona gráficos e imágenes → añadir a colección (base64)</li><li>Selecciona citas relevantes → colección</li><li>Guarda instantáneo <em>"Primera revisión"</em></li><li>Exporta colección como JSON (backup)</li><li>Continúa análisis, añade anotaciones → guarda instantáneo <em>"Anotaciones completas"</em></li><li>Extrae un capítulo → Noesis Editor se abre con chunks en Panel de Inspección → estructura el reporte</li><li>Exporta a DOCX para revisión colegial</li></ol>',
    'guida.profile.blogger.btn': '📝 Bloguero/Creador — Flujo rápido',
    'guida.profile.blogger.body': '<ol style="padding-left:20px; line-height:2;"><li>Lee el libro con Noesis</li><li>Selecciona pasajes para la review → colección</li><li>Extrae capítulos relevantes</li><li>Guarda instantáneo <em>"Material collectado"</em></li><li>Extrae el capítulo → Noesis Editor se abre directamente</li><li>Escribe la review en el editor WYSIWYG</li><li>Copia HTML → pega en tu CMS</li></ol>',
    'guida.profile.multilingual.btn': '🌍 Lector multilingüe — Estudio de idiomas',
    'guida.profile.multilingual.body': '<ol style="padding-left:20px; line-height:2;"><li>Importa novela en idioma objetivo</li><li>Habilita traducción del navegador para idioma nativo</li><li>Lee con referencia dual (original + traducción)</li><li>Resalta palabras nuevas (rosa)</li><li>Extrae el capítulo → Guarda instantáneo <em>"Sesión 1 vocabulario"</em></li><li>Añade oraciones difíciles a colección</li><li>Exporta colección JSON → archivo personal</li></ol>',
