    'reading.pagenav.next': 'Noesis Editor →',
    'reading.img.toc': 'Noesis Reading TOC-Sidebar — hierarchisches Inhaltsverzeichnis',
    'reading.img.toc.caption': '☰ Hierarchische TOC-Sidebar — erweiterbar bis zu 3 Ebenen mit direkter Navigation',
    'reading.themes.label': 'Lesethemen',
    'reading.themes.h2': '15 Themen in <em>5 Gruppen</em>',
    'reading.themes.p': 'Das Anzeigeeinstellungen-Panel bietet 15 vordefinierte Themes, organisiert in 5 Gruppen nach Helligkeit. Sie können auch Hintergrund- und Textfarben direkt mit den Auswahlfeldern anpassen.',
    'reading.themegroup.light': 'Hell',
    'reading.themegroup.gray': 'Grau',
    'reading.themegroup.dark': 'Dunkel',
    'reading.img.themes': 'Lesethema-Auswahl — 15 Themen in 5 Gruppen',
    'reading.img.themes.caption': '🎨 Anzeige-Panel — 15 Themen in 5 Gruppen, anpassbare Typografie',
    'reading.highlight.label': 'Hervorhebung',
    'reading.highlight.h2': '3-Farben-<em>Annotations</em>system',
    'reading.highlight.p': 'Hervorhebungen werden in <code>localStorage</code> mittels CFI (Canonical Fragment Identifiers) gespeichert — ein standardisiertes System zum Referenzieren von Positionen in EPUBs. Sie überstehen Seiten-Neuladen und erneutes Öffnen des Buches.',
    'reading.hl.yellow.h': 'Gelb — Allgemeine Konzepte',
