    // HELPERS.HTML
    // ════════════════════════════════════════
    'helpers.meta.desc': 'ePub Slimmer, Multi ePub Slimmer, ePub Splitter und PDF.js Viewer — zusätzliche Werkzeuge zur Verwaltung Ihrer EPUBs im Browser.',
    'helpers.hero.badge': 'Benutzerhandbuch · Hilfswerkzeuge',
    'helpers.hero.h1': '<em>Zusätzliche</em> Werkzeuge',
    'helpers.hero.p': 'Vier Werkzeuge zur Verwaltung Ihrer EPUBs: hochwertiger PDF-Viewer, Einzel- und Stapelbildkomprimierung und Splitter zum Extrahieren von Kapiteln als separate Dateien. Alles im Browser.',
    'helpers.pdfjs.label': 'Werkzeug 1',
    'helpers.pdfjs.h2': 'Mozilla <em>PDF.js Viewer</em>',
    'helpers.pdfjs.p': 'Hochwertige Darstellung extrahierter Kapitel über den Open-Source-PDF-Viewer von Mozilla. In den Kapitel-Export-Workflow integriert.',
    'helpers.pdfjs.view.h': '📖 Erweiterte Ansicht',
    'helpers.pdfjs.view.p': 'Hochwertige PDF-Darstellung mit Unterstützung für eingebettete Schriftarten, komplexe Layouts und präzise Farben — überlegen zum Browser-Druckdialog.',
    'helpers.pdfjs.zoom.h': '🔍 Zoom und Navigation',
    'helpers.pdfjs.zoom.p': 'Hinein- und herauszoomen mit präzisem Prozentsatz, Seitenavigation mit direkter Nummern-Eingabe, Vollbildansicht.',
    'helpers.pdfjs.search.h': '🔎 Textsuche',
    'helpers.pdfjs.search.p': 'Volltextsuche im PDF mit hervorgegebenen Ergebnissen. Nützlich zum schnellen Finden bestimmter Begriffe in langen Kapiteln.',
    'helpers.pdfjs.print.h': '🖨️ Direktes Drucken',
    'helpers.pdfjs.print.p': 'Drucken Sie das PDF direkt aus dem Viewer unter Verwendung der nativen Browser-Funktionen, mit druck-optimiertem Layout.',
    'helpers.img.mozilla': 'PDF.js Viewer mit extrahiertem Kapitel',
    'helpers.img.mozilla.caption': '📖 PDF.js Viewer — hochwertige Darstellung des extrahierten Kapitels',
    'helpers.slimmer.label': 'Werkzeug 2',
    'helpers.slimmer.h2': '<em>ePub Slimmer</em>',
    'helpers.slimmer.p': 'Komprimiert Bilder in einer EPUB-Datei, um die Größe zu reduzieren. Nützlich für EPUBs mit vielen hochauflösenden Bildern, die das Laden verlangsamen.',
    'helpers.slimmer.compress.h': '🖼️ Bildkomprimierung',
    'helpers.slimmer.compress.p': 'Komprimiert alle Bilder im EPUB zu JPEG mit konfigurierbarer Qualität. Behält Seitenverhältnis und Bildstruktur bei.',
    'helpers.slimmer.quality.h': '⚙️ Konfigurierbare Qualität',
    'helpers.slimmer.quality.p': 'Komprimierungsqualität anpassen (0–100). Werte zwischen 60–80 bieten eine gute Balance zwischen Größe und Qualität für die meisten EPUBs.',
    'helpers.slimmer.nodrm.h': '🔒 Kein DRM',
    'helpers.slimmer.nodrm.p': 'Funktioniert nur mit DRM-freien EPUBs. Geschützte Dateien können nicht verarbeitet werden.',
    'helpers.multislimmer.label': 'Werkzeug 3',
    'helpers.multislimmer.h2': '<em>Multi ePub Slimmer</em>',
    'helpers.multislimmer.p': 'Stapelversion von ePub Slimmer. Verarbeiten Sie mehrere EPUB-Dateien gleichzeitig mit denselben Komprimierungseinstellungen.',
    'helpers.multislimmer.batch.h': '📚 Stapelverarbeitung',
    'helpers.multislimmer.batch.p': 'Wählen Sie mehrere EPUBs auf einmal. Jedes wird unabhängig komprimiert und automatisch heruntergeladen.',
    'helpers.multislimmer.progress.h': '📊 Fortschritt',
    'helpers.multislimmer.progress.p': 'Fortschrittsbalken für jedes EPUB während der Verarbeitung. Verarbeitete Dateien erscheinen in der Ergebnisliste, sobald sie fertig sind.',
    'helpers.splitter.label': 'Werkzeug 4',
    'helpers.splitter.h2': '<em>ePub Splitter</em>',
    'helpers.splitter.p': 'Teilt ein EPUB in einzelne Kapiteldateien. Jedes Kapitel wird als eigenständige EPUB gespeichert — nützlich für Lesetools, die große EPUBs schlecht handhaben.',
    'helpers.splitter.split.h': '✂️ Nach Kapitel teilen',
    'helpers.splitter.split.p': 'Jeder Eintrag in der EPUB-Spine wird eine separate EPUB mit korrekten Metadaten. Kapitelnamen werden aus der TOC übernommen.',
    'helpers.splitter.download.h': '📦 ZIP-Download',
    'helpers.splitter.download.p': 'Alle geteilten EPUBs werden in einer einzigen ZIP-Datei zum Download verpackt. Keine Zwischenschritte.',
    'helpers.pdfjs.callout': '<strong>So greifen Sie auf den PDF Viewer zu</strong> — Der PDF Viewer wird über die <strong>👁 PDF Viewer</strong>-Schaltfläche in der extrahierten Kapitel-Toolbar aktiviert. Es ist keine separate Seite — es ist in den Kapitel-Export-Workflow integriert.',
    'helpers.pdfjs.meta.p': 'Hochwertige PDF-Darstellung direkt im Browser',
    'helpers.slimmer.meta.p': 'Bildkomprimierung für eine einzelne EPUB-Datei',
    'helpers.slimmer.link': 'Werkzeug öffnen →',
    'helpers.multislimmer.meta.p': 'Stapelkomprimierung von bis zu 10 EPUB-Dateien',
    'helpers.multislimmer.link': 'Werkzeug öffnen →',
    'helpers.multislimmer.queue.h': '🔢 Warteschlange mit individuellem Status',
    'helpers.multislimmer.queue.p': 'Jede Datei zeigt ihren eigenen Status: <span class="badge badge-gray">ausstehend</span> → <span class="badge badge-violet">verarbeitet</span> → <span class="badge badge-green">fertig</span> oder <span class="badge badge-red">Fehler</span>.',
    'helpers.multislimmer.error.h': '⚠️ Fehlerbehandlung',
    'helpers.multislimmer.error.p': 'Wenn eine Datei fehlschlägt (korruptes EPUB, nicht unterstütztes Format) werden die anderen weiterverarbeitet. Klare Fehlermeldungen für jede problematische Datei.',
    'helpers.splitter.meta.p': 'Ausgewählte Kapitel als separate EPUB-Dateien extrahieren',
    'helpers.splitter.link': 'Werkzeug öffnen →',
    'helpers.splitter.callout': '<strong>Unterschied zur Kapitelextraktion</strong> — Der Splitter erstellt eigenständige <code>.epub</code>-Dateien (importierbar in andere Reader). Die Kapitel extrahieren-Funktion in Noesis erstellt eigenständige HTML-Dokumente mit der integrierten Noesis-Toolbar. Sie sind komplementäre Werkzeuge mit unterschiedlichen Zwecken.',
    'helpers.pagenav.prev': '← Sammlungen',
